-- =========================================================
-- Migration: Grades unique constraint + Secondary Classes
-- Run this in Supabase SQL Editor
-- =========================================================

-- 1. Add unique constraint to grades table so upsertGrade works
ALTER TABLE grades
  ADD CONSTRAINT IF NOT EXISTS grades_unique
  UNIQUE (student_id, subject_id, class_id, grade_type, semester);

-- =========================================================
-- 2. Insert Secondary School Classes (grades 10, 11, 12)
-- ============================================================
-- Migration 20260312000000: Secondary school classes + timetable
-- المرحلة الثانوية: الصفوف 10-11-12 (18 فصل)
-- ============================================================

-- Step 1: Classes
ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name;

-- Step 2: Teacher-Class Assignments
ON CONFLICT (teacher_id, class_id) DO NOTHING;

-- Step 3: Timetable (auto-generated distribution)
ON CONFLICT (class_id, day_of_week, period_number) DO UPDATE SET
  subject_id=EXCLUDED.subject_id, teacher_id=EXCLUDED.teacher_id,
  start_time=EXCLUDED.start_time, end_time=EXCLUDED.end_time;